const fs = require('fs');

fs.writeFile('log.txt', 'Start of log\n', err => {
  if (err) return console.error(err);
  console.log('File created');
});

fs.appendFile('log.txt', 'Another line\n', err => {
  if (err) console.error(err);
  else console.log('Appended');
});

